    x = x_start
    for _ in range(max_iterations):
        # Calculate the derivative using finite difference
        derivative = (func(x + step_size) - func(x)) / step_size

        # If the derivative is close to zero, we have found a local maximum or minimum
        if abs(derivative) < tolerance:
            break

        # Update x by moving in the direction of the slope
        x += step_size if derivative > 0 else -step_size

    return x, func(x)

